import { TestBed } from '@angular/core/testing';
import { AppComponent } from './app.component';
import { RouterModule } from '@angular/router';

describe('AppComponent', () => {
  beforeEach(async () => {
    await TestBed.configureTestingModule({
      imports: [AppComponent, RouterModule.forRoot([])],
    }).compileComponents();
  });

  it('should create the app', () => {
    const fixture = TestBed.createComponent(AppComponent);
    const app = fixture.componentInstance;
    expect(app).toBeTruthy();
  });

  it('should have title "issue-tracker"', () => {
    const fixture = TestBed.createComponent(AppComponent);
    const app = fixture.componentInstance;
    expect(app.title).toBe('issue-tracker');
  });
});

@use '@angular/material' as mat;

// ============================================================
// Material theme — custom deep-purple/amber brand
// Note: @angular/material 17.3 ships the M2 Sass API; using
// mat.define-light-theme. mat.define-theme (M3) is in v18+.
// ============================================================

@include mat.core();

$primary: mat.define-palette(mat.$deep-purple-palette, 600);
$accent:  mat.define-palette(mat.$amber-palette, A200, A100, A400);
$warn:    mat.define-palette(mat.$red-palette);

$theme: mat.define-light-theme((
  color: (
    primary: $primary,
    accent:  $accent,
    warn:    $warn,
  ),
  typography: mat.define-typography-config(
    $font-family: 'Roboto, "Helvetica Neue", sans-serif',
  ),
));

@include mat.all-component-themes($theme);

