//
// Spacing:   --it-space-{1-6}         4 8 12 16 24 32 px
// Radius:    --it-radius-{sm,md,lg}   4 8 16 px
// Elevation: --it-shadow-{1,2}        low / medium box-shadows
// Surface:   --it-surface             app panel / card bg
//            --it-background          page bg
// Status (IssueStatus enum):
//   --it-status-open        open
//   --it-status-in-progress in_progress
//   --it-status-done        done
//   --it-status-closed      closed
// Priority (IssuePriority enum):
//   --it-priority-low       low
//   --it-priority-medium    medium
//   --it-priority-high      high
//   --it-priority-critical  critical
// ============================================================

:root {
  // Spacing
  --it-space-1: 4px;
  --it-space-2: 8px;
  --it-space-3: 12px;
  --it-space-4: 16px;
  --it-space-5: 24px;
  --it-space-6: 32px;

  // Radius
  --it-radius-sm: 4px;
  --it-radius-md: 8px;
  --it-radius-lg: 16px;

  // Elevation
  --it-shadow-1: 0 1px 3px rgba(0, 0, 0, 0.12), 0 1px 2px rgba(0, 0, 0, 0.08);
  --it-shadow-2: 0 3px 6px rgba(0, 0, 0, 0.15), 0 2px 4px rgba(0, 0, 0, 0.12);

  // Surface / background
  --it-surface: #f5f0ff;
  --it-background: #ede7f6;

  // Status (IssueStatus enum values → kebab-cased token names)
  --it-status-open:        #1565c0;
  --it-status-in-progress: #e65100;
  --it-status-done:        #2e7d32;
  --it-status-closed:      #616161;

  // Priority (IssuePriority enum values → kebab-cased token names)
  --it-priority-low:      #43a047;
  --it-priority-medium:   #fb8c00;
  --it-priority-high:     #e53935;
  --it-priority-critical: #b71c1c;
}

// ============================================================
// Global reset
// ============================================================

*, *::before, *::after {
  box-sizing: border-box;
}

html, body {
  height: 100%;
}

body {
  margin: 0;
  background: var(--it-surface);
  font-family: Roboto, "Helvetica Neue", sans-serif;
}

